from flask import Flask, send_file, abort, request
from pathlib import Path
import os
import re

app = Flask(__name__)

UPLOADS_DIR = Path(__file__).parent / 'uploads'
UPLOADS_DIR.mkdir(exist_ok=True)

LEGACY_FILENAME_PATTERNS = {
    r'^file_(\d+)_v(\d+)\.(.+)$': lambda m: f"file_{m.group(1)}_v{m.group(2)}.{m.group(3)}",
    r'^document-(\d{4})-(\d{2})-(\d{2})\.(.+)$': lambda m: f"document-{m.group(1)}-{m.group(2)}-{m.group(3)}.{m.group(4)}",
    r'^legacy_(.+)$': lambda m: f"legacy_{m.group(1)}",
}

FILE_ID_MAPPING = {}

def initialize_file_mapping():
    """Build server-side mapping of file IDs to actual paths"""
    if UPLOADS_DIR.exists():
        for file_path in UPLOADS_DIR.rglob('*'):
            if file_path.is_file():
                relative_path = file_path.relative_to(UPLOADS_DIR)
                file_id = str(relative_path).replace(os.sep, '/')
                FILE_ID_MAPPING[file_id] = file_path

def is_safe_path(base_dir: Path, user_path: str) -> tuple[bool, Path]:
    """
    Canonicalize and validate that the resolved path is within base_dir.
    Returns (is_safe, resolved_path)
    """
    if not user_path:
        return False, None
    
    if os.path.isabs(user_path):
        return False, None
    
    if '..' in Path(user_path).parts:
        return False, None
    
    try:
        base_resolved = base_dir.resolve()
        full_path = (base_dir / user_path).resolve()
        
        try:
            full_path.relative_to(base_resolved)
            return True, full_path
        except ValueError:
            return False, None
            
    except (OSError, RuntimeError):
        return False, None

def normalize_legacy_filename(filename: str) -> str:
    """Convert legacy filename patterns to current format"""
    for pattern, converter in LEGACY_FILENAME_PATTERNS.items():
        match = re.match(pattern, filename)
        if match:
            return converter(match)
    return filename

def find_file_with_legacy_support(filename: str) -> Path:
    """
    Locate file using allowlisted file ID mapping with legacy name support.
    """
    normalized = normalize_legacy_filename(filename)
    
    if normalized in FILE_ID_MAPPING:
        return FILE_ID_MAPPING[normalized]
    
    if filename in FILE_ID_MAPPING:
        return FILE_ID_MAPPING[filename]
    
    return None

@app.route('/uploads/<path:filename>')
def serve_upload(filename):
    """
    Serve static files from uploads directory with legacy filename support.
    Uses secure path validation and server-side file mapping.
    """
    file_path = find_file_with_legacy_support(filename)
    
    if file_path and file_path.exists() and file_path.is_file():
        is_safe, resolved_path = is_safe_path(UPLOADS_DIR, file_path.relative_to(UPLOADS_DIR))
        
        if is_safe and resolved_path == file_path:
            return send_file(file_path)
    
    is_safe, resolved_path = is_safe_path(UPLOADS_DIR, filename)
    
    if not is_safe:
        abort(400, description="Invalid file path")
    
    if not resolved_path.exists():
        abort(404, description="File not found")
    
    if not resolved_path.is_file():
        abort(400, description="Invalid file")
    
    return send_file(resolved_path)

@app.route('/legacy/download')
def legacy_download():
    """
    Legacy endpoint that accepts file parameter.
    Uses allowlisted file IDs instead of raw paths.
    """
    file_id = request.args.get('file', '')
    
    if not file_id:
        abort(400, description="Missing file parameter")
    
    file_path = find_file_with_legacy_support(file_id)
    
    if not file_path:
        is_safe, resolved_path = is_safe_path(UPLOADS_DIR, file_id)
        
        if not is_safe:
            abort(400, description="Invalid file identifier")
        
        if not resolved_path.exists() or not resolved_path.is_file():
            abort(404, description="File not found")
        
        file_path = resolved_path
    
    return send_file(file_path, as_attachment=True)

@app.route('/files/<file_id>')
def serve_by_id(file_id):
    """
    Serve files using allowlisted file identifiers.
    Most secure approach - no direct path manipulation.
    """
    file_path = find_file_with_legacy_support(file_id)
    
    if not file_path or not file_path.exists() or not file_path.is_file():
        abort(404, description="File not found")
    
    is_safe, _ = is_safe_path(UPLOADS_DIR, file_path.relative_to(UPLOADS_DIR))
    if not is_safe:
        abort(400, description="Invalid file")
    
    return send_file(file_path)

@app.before_request
def refresh_file_mapping():
    """Refresh file mapping periodically for new uploads"""
    if not hasattr(app, '_mapping_initialized'):
        initialize_file_mapping()
        app._mapping_initialized = True

if __name__ == '__main__':
    initialize_file_mapping()
    app.run(debug=True)